<?php
// partials/sidebar.php
// Expects bootstrap.php to have been included earlier so BASE_PATH, APP_ROOT and $currentPath are available.

// Defensive defaults
if (!defined('BASE_PATH')) define('BASE_PATH', '');
if (!defined('APP_ROOT')) define('APP_ROOT', __DIR__ . '/..');
if (!isset($currentPath)) $currentPath = parse_url($_SERVER['REQUEST_URI'] ?? '', PHP_URL_PATH);
if (session_status() === PHP_SESSION_NONE) session_start();

// Only define url_path() if it doesn't exist already
if (!function_exists('url_path')) {
  function url_path($path)
  {
    $base = rtrim(BASE_PATH, '/');
    $p = ltrim($path, '/');
    return ($base === '' ? '' : $base) . '/' . $p;
  }
}

// Only define nav_active() if it doesn't exist already
if (!function_exists('nav_active')) {
  function nav_active($relativePath)
  {
    global $currentPath;

		$normalize = function ($path) {
			$p = parse_url((string)$path, PHP_URL_PATH) ?? '';
			$p = trim($p);

			$base = rtrim((string)BASE_PATH, '/');
			if ($base !== '' && strpos($p, $base . '/') === 0) {
				$p = substr($p, strlen($base));
			} elseif ($base !== '' && $p === $base) {
				$p = '/';
			}

			$p = '/' . ltrim($p, '/');
			$p = preg_replace('#/(?:index|home)\.php$#i', '', $p);
			$p = rtrim($p, '/');

			return $p === '' ? '/' : $p;
		};

		$target = $normalize(url_path($relativePath));
		$cur = $normalize($currentPath ?? '/');

		return ($cur === $target || strpos($cur, $target . '/') === 0) ? 'active' : '';
  }
}

if (!function_exists('is_valid_hex_color')) {
	function is_valid_hex_color($value)
	{
		return is_string($value) && preg_match('/^#[0-9A-Fa-f]{6}$/', $value);
	}
}

if (!function_exists('hex_mix')) {
	function hex_mix($hex, $mixRgb, $ratio)
	{
		$h = ltrim($hex, '#');
		$r = hexdec(substr($h, 0, 2));
		$g = hexdec(substr($h, 2, 2));
		$b = hexdec(substr($h, 4, 2));

		$rr = (int)round($r * (1 - $ratio) + $mixRgb[0] * $ratio);
		$gg = (int)round($g * (1 - $ratio) + $mixRgb[1] * $ratio);
		$bb = (int)round($b * (1 - $ratio) + $mixRgb[2] * $ratio);

		return sprintf('#%02x%02x%02x', $rr, $gg, $bb);
	}
}

if (!function_exists('hex_to_rgba')) {
	function hex_to_rgba($hex, $alpha)
	{
		$h = ltrim($hex, '#');
		$r = hexdec(substr($h, 0, 2));
		$g = hexdec(substr($h, 2, 2));
		$b = hexdec(substr($h, 4, 2));
		return 'rgba(' . $r . ',' . $g . ',' . $b . ',' . $alpha . ')';
	}
}

$themeColor = null;
if (session_status() === PHP_SESSION_ACTIVE && isset($_SESSION['acc_primary_color']) && is_valid_hex_color($_SESSION['acc_primary_color'])) {
	$themeColor = strtolower($_SESSION['acc_primary_color']);
} elseif (session_status() === PHP_SESSION_ACTIVE && isset($_SESSION['user']) && isset($mysqli) && $mysqli) {
	$stmt = $mysqli->prepare('SELECT acc_primary_color FROM account WHERE username = ? LIMIT 1');
	if ($stmt) {
		$u = (string)$_SESSION['user'];
		$stmt->bind_param('s', $u);
		$stmt->execute();
		$row = $stmt->get_result()->fetch_assoc();
		$stmt->close();
		if (!empty($row['acc_primary_color']) && is_valid_hex_color($row['acc_primary_color'])) {
			$themeColor = strtolower($row['acc_primary_color']);
			$_SESSION['acc_primary_color'] = $themeColor;
		}
	}
}
?>

<?php if ($themeColor): ?>
<style>
	:root {
		--teal: <?php echo htmlspecialchars($themeColor); ?>;
		--teal-light: <?php echo htmlspecialchars(hex_mix($themeColor, [255, 255, 255], 0.18)); ?>;
		--teal-glow: <?php echo htmlspecialchars(hex_to_rgba($themeColor, 0.18)); ?>;
		--teal-dim: <?php echo htmlspecialchars(hex_to_rgba($themeColor, 0.08)); ?>;
	}
</style>
<?php endif; ?>

